const webhookItems = $('Webhook').all();
const result = [];

for (let i = 0; i < webhookItems.length; i++) {
  const data = webhookItems[i].json.body || webhookItems[i].json || {};

  // Extrair dados críticos
  const complexidade = data.complexidade;
  const dataServicoStr = data.data_servico || new Date().toISOString();
  const dataServico = new Date(dataServicoStr);
  const horaServico = dataServico.getHours();
  const diaSemana = dataServico.getDay();

  const temGastronomia = data.equipamentos && (data.equipamentos.includes('chapa') || data.equipamentos.includes('fritadeira') || data.gastronomia === true);

  // Validar dados críticos
  if (!complexidade) {
    result.push({
      json: {
        status: "Sob Avaliação Técnica",
        motivo: "Faltam dados críticos (complexidade) para calcular a mão de obra."
      }
    });
    continue;
  }

  // Hora técnica base
  let horaTecnica = 120;
  if (complexidade === 'critica') horaTecnica = 220;

  // Urgência / Multiplicadores de Tempo
  let multiplicadorUrgencia = 1.0;
  if (diaSemana === 0) {
    multiplicadorUrgencia = 2.5; // Domingo
  } else if (horaServico >= 18 || horaServico < 6) {
    multiplicadorUrgencia = 2.0; // Noite
  }

  // Risco
  let multiplicadorRisco = 1.0;
  if (temGastronomia) {
    multiplicadorRisco = 1.2;
  }

  // Cálculo final
  const horasEstimadas = data.horas_estimadas || 1;
  const custoInterno = horaTecnica * multiplicadorUrgencia * multiplicadorRisco * horasEstimadas;

  // Formatação da saída - não expor custo interno
  const margemLucro = 1.4;
  const precoRecomendado = Math.round(custoInterno * margemLucro * 100) / 100;
  const faixaMin = Math.round(precoRecomendado * 0.9 * 100) / 100;
  const faixaMax = Math.round(precoRecomendado * 1.15 * 100) / 100;

  result.push({
    json: {
      status: "Sucesso",
      preco_recomendado: precoRecomendado,
      faixa_comercial: {
        min: faixaMin,
        max: faixaMax
      },
      imposto_estimado_percentual: "imposto_estimado_percentual", // Pendente de validação contábil
      detalhes_ocultos: "Custo interno ocultado conforme diretriz.",
      multiplicadores_aplicados: {
        urgencia: multiplicadorUrgencia,
        risco: multiplicadorRisco,
        domingo: diaSemana === 0,
        noturno: (horaServico >= 18 || horaServico < 6),
        gastronomia: temGastronomia
      }
    }
  });
}

return result;

